SELECT AVG(bet_amount) AS average_bet
FROM game_history
WHERE game_id = 1;

SELECT COUNT(*) AS total_games_played
FROM game_history
WHERE player_id = 0;

SELECT total_games
FROM game_stats
WHERE game_id = 1;

SELECT player_id
FROM player_sessions
WHERE total_won > total_bet;

SELECT SUM(bet_amount) AS total_bets
FROM game_history
WHERE game_id = 1;

SELECT total_bet, total_won
FROM player_sessions
WHERE session_id = 0;

SELECT bet_amount, win_amount
FROM game_history
WHERE player_id = 1;

SELECT COUNT(*) AS total_games_played
FROM game_history
WHERE game_id = 1;
